// index.json からサマリーを生成
const index = JSON.parse($input.first().json.data);
const runs = index.runs || [];
const latestRun = runs[runs.length - 1] || {};
const entries = Object.values(index.entries || {});

// 本日追加分
const today = new Date().toISOString().split('T')[0];
const todayEntries = entries.filter(e => (e.discovered_at || '').startsWith(today));

// スコアTOP5
const top5 = [...entries].sort((a, b) => (b.design_score || 0) - (a.design_score || 0)).slice(0, 5);

// トレンドタグ
const tagMap = {};
entries.forEach(e => (e.tags || []).forEach(t => tagMap[t] = (tagMap[t] || 0) + 1));
const topTags = Object.entries(tagMap).sort((a, b) => b[1] - a[1]).slice(0, 8);

return [{
  json: {
    total: entries.length,
    new_today: todayEntries.length,
    avg_score: latestRun.avg_score || 0,
    queries: latestRun.queries || 0,
    elapsed: latestRun.elapsed_sec || 0,
    change_detected: (latestRun.change_detection || {}).changed || 0,
    screenshots: latestRun.screenshots || 0,
    top5: top5.map(e => `[${e.design_score}] ${e.aesthetic} - ${e.domain}`),
    today_entries: todayEntries.map(e => `[${e.design_score}] ${e.aesthetic} - ${e.url}`),
    top_tags: topTags.map(([t, c]) => `${t}(${c})`),
    has_news: todayEntries.length > 0 || (latestRun.change_detection || {}).changed > 0
  }
}];
